query:
SELECT r.id, r.roomNo, r.rounds, r.currentRound, r.status, r.winnerId, 
       (SELECT COUNT(*) FROM arenaRoundResults rr WHERE rr.roomId = r.id) as resultCount
FROM arenaRooms r WHERE r.roomNo = 336676;

SELECT roundNo, playerId, goodsName, goodsValue FROM arenaRoundResults 
WHERE roomId = (SELECT id FROM arenaRooms WHERE roomNo = 336676) 
ORDER BY roundNo, playerId;

